import{_ as n,o,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"F17: 籌碼分佈與法人動態分析","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/財務組/F17_籌碼分佈與法人動態分析_投資研究員.md","filePath":"32Ｑ題本＿重要/財務組/F17_籌碼分佈與法人動態分析_投資研究員.md"}'),i={name:"32Ｑ題本＿重要/財務組/F17_籌碼分佈與法人動態分析_投資研究員.md"};function l(s,t,a,g,c,_){return o(),r("div",null,[...t[0]||(t[0]=[e('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="f17-籌碼分佈與法人動態分析" tabindex="-1">F17: 籌碼分佈與法人動態分析 <a class="header-anchor" href="#f17-籌碼分佈與法人動態分析" aria-label="Permalink to &quot;F17: 籌碼分佈與法人動態分析&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-F17</li><li><strong>題目：</strong> 外資、投信與自營商的近期買賣超動向為何？千張大戶持股比例是否發生結構性變化？</li><li><strong>推薦專家：</strong> 投資研究員 (<code>finance-investment-researcher</code>)</li><li><strong>推薦理由：</strong> 專精於「博弈分析」與「資金流向追蹤」。具備解析機構投資人（Big Money）盤後數據的能力，能識別「投信鎖碼股」與「外資套利行為」，判定股價動能的持久性。</li><li><strong>意圖：</strong> 執行「法人對決與籌碼集中度審計」。分析三大法人的合計進出趨勢，判定資金是否具備「共識性合力」。識別散戶與法人的籌碼換手特徵，預警「派發期」風險或捕捉「收集期」機會。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心數據基石：FinMind】</strong>：調用 <code>TaiwanStockInstitutionalHolding</code> 獲取外資、投信買賣超數據。</li><li><strong>【結構穿透：FinMind】</strong>：調用 <code>TaiwanStockShareholdingSpread</code> 分析 400 張與 1000 張大戶持股比例的週變動。</li><li><strong>【情緒輔助：Web Search】</strong>：檢索「[公司名] 借券賣出 餘額」、「[公司名] 融資餘額 變動」。</li></ol></li><li><strong>邏輯：</strong> 執行「法人鎖碼算則」——分析法人買超是否伴隨大戶持股上升；執行「散戶背離測試」——判定散戶人數增長是否與股價漲幅呈負相關（即：派發警報）。</li><li><strong>來源：</strong> <code>FinMind</code></li></ul><h2 id="🛠️-工作流程-按順序執行-不得跳過" tabindex="-1">🛠️ 工作流程（按順序執行，不得跳過） <a class="header-anchor" href="#🛠️-工作流程-按順序執行-不得跳過" aria-label="Permalink to &quot;🛠️ 工作流程（按順序執行，不得跳過）&quot;">​</a></h2><ol><li><strong>取數據</strong>：<code>python3 數據採集器.py institutional [股號]</code> → 抓外資/投信/自營商買賣超</li><li><strong>判讀</strong>：法人連續買超 = 鎖碼；散戶人數暴增 = 派發警訊</li><li><strong>搜尋</strong>：用 <code>web_search</code> 搜尋融資餘額和借券賣出數據</li><li><strong>撰寫報告</strong>：依下方回答模板結構產出</li></ol><p>⚠️ <strong>常見陷阱</strong>：①答詢詳解 ≥200 字、專家評析 ≥200 字；②空頭視角 ≥2 個（法人冷落、流動性差）；③量化法人買賣超張數</p><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【籌碼事實優先】</strong>：智慧體<strong>必須</strong>列出最近 4 週的「法人合計進出張數」與「大戶持股比例」。禁止在未分析具體數據前給予「法人看好」之結論。</li><li><strong>【鎖碼特徵偵測】</strong>：若法人連續買超 10 天以上且大戶持股佔比創 12 週新高，智慧體必須判定為「籌碼高度鎖死」，評估其向上噴發之潛力。</li><li><strong>【派發紅燈預警】</strong>：若股價上漲但「散戶持股人數」同步創高且「千張大戶比例」下降，必須強制發出「高位派發、法人撤退」警訊。</li><li><strong>【描述指標】</strong>：絕對禁用「吸籌」、「換手」。必須量化為具體的「法人買賣超累計張數」、「籌碼集中度 bps」與「戶數變動率」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【f17-專家答詢】投資研究員-finance-investment-researcher" tabindex="-1">【F17 專家答詢】投資研究員 (finance-investment-researcher) <a class="header-anchor" href="#【f17-專家答詢】投資研究員-finance-investment-researcher" aria-label="Permalink to &quot;【F17 專家答詢】投資研究員 (finance-investment-researcher)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「籌碼質量+動能判定」結構（例：法人連買 X 週，大戶比例升 Z%，屬 [主力鎖碼/散戶陷阱]，股價動能預期為 [轉強/陰跌]）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：外資與投信同步呈現「方向性合力」大舉買進，且籌碼高度集中於千張大戶，散戶人數持續減少，呈現極其完美的「籌碼收縮」攻擊態勢。</li><li><strong>A (良)</strong>：法人買賣分歧但在大戶持股未鬆動的前提下，籌碼仍屬穩定，股價處於健康的法人換手階段。</li><li><strong>B (持平)</strong>：法人大規模撤出且散戶融資餘額暴增，籌碼呈現「渙散且由強勢手流向弱勢手」的顯著特徵，面臨極大的多殺多風險。</li></ul></li><li><strong>【證據來源】數據溯源</strong>：必須精確標註 FinMind <code>institutional</code> 買賣日期與交易所股權分散表週次。</li><li><strong>【專家評析】核心分析與洞察內容</strong>：特別關注「投信持股比例」。若標的屬成長股且投信持股逾 15%，專家在此處應警告「結帳壓力」，因法人持股過高往往代表買盤枯竭，稍有風吹草動即會產生踐踏效應。</li></ul>',12)])])}const u=n(i,[["render",l]]);export{h as __pageData,u as default};
